        if in_str:
            if escaped:
                escaped = False
            elif ch == "\\":
                escaped = True
            elif ch == '"':
                in_str = False
            continue
        if ch == '"':
            in_str = True
        elif ch == open_ch:
            depth += 1
        elif ch == close_ch:
            depth -= 1
            if depth == 0:
                return text[start:i + 1]
    return None

def _extract_json(text: str):
    candidate = text.strip()
    # Strip a ```json ... ``` fence if present.
    if candidate.startswith("```"):
        inner = candidate[3:]
        if inner[:4].lower() == "json":
            inner = inner[4:]
        candidate = inner.rsplit("```", 1)[0].strip()
    try:
        return json.loads(candidate)
    except json.JSONDecodeError:
        pass
    span = _first_balanced_json(candidate)
    if span is not None:
        try:
            return json.loads(span)
        except json.JSONDecodeError as exc:
            raise Exception(f"Reply was not valid JSON: {text[:200]!r}") from exc
    raise Exception(f"No JSON value found in reply: {text[:200]!r}")

# Test edge case: empty reply
try:
    result = _extract_json("")
    print("Empty string: {}".format(result))
except Exception as e:
    print("Empty string error: {}".format(e))

# Test edge case: only whitespace
try:
    result = _extract_json("   \n  \t  ")
    print("Whitespace: {}".format(result))
except Exception as e:
    print("Whitespace error: {}".format(e))

# Test edge case: markdown fence with no JSON inside
try:
    result = _extract_json("```json\n```")
    print("Empty fence: {}".format(result))
except Exception as e:
    print("Empty fence error: {}".format(e))
